// migrated-by: codex-migrate v0.1
'use strict';

const { execFileSync } = require('node:child_process');

const VERIFICATION_ITEMS = Object.freeze([
  'file_existence',
  'status_complete',
  'tdd_state_transitions',
  'sensor_results_present',
  'out_of_scope_detection',
  'baseline_chain_continuity',
  'tdd_hard_fail',
  'verification_cmd_rerun',
]);

// STRICT_TRANSITIONS must be a superset of phase-guard-core.js VALID_TRANSITIONS
// so inline-path receipts (generated by the hook state machine) don't get
// rejected by the delegated verify. (W14 — fixes FSM divergence.)
// phase-guard FSM (see hooks/scripts/phase-guard-core.js:36-47):
//   PENDING → RED | SPIKE
//   RED → RED_VERIFIED | SPIKE
//   RED_VERIFIED → GREEN_ELIGIBLE | SPIKE
//   GREEN_ELIGIBLE → GREEN | SPIKE
//   GREEN → SENSOR_RUN | REFACTOR | PENDING | SPIKE
//   SENSOR_RUN → SENSOR_FIX | SENSOR_CLEAN
//   SENSOR_FIX → GREEN | RED
//   SENSOR_CLEAN → REFACTOR | PENDING | SPIKE
//   REFACTOR → GREEN | PENDING | SPIKE
//   SPIKE → PENDING
// Delegated path may additionally record PENDING→RED_VERIFIED as a single
// compound edge (when RED is verified inline in agent prompt, the intermediate
// RED state may not be separately recorded). Both edges are accepted.
const STRICT_TRANSITIONS = new Set([
  // phase-guard FSM edges
  'PENDING→RED', 'PENDING→SPIKE',
  'RED→RED_VERIFIED', 'RED→SPIKE',
  'RED_VERIFIED→GREEN_ELIGIBLE', 'RED_VERIFIED→SPIKE',
  'GREEN_ELIGIBLE→GREEN', 'GREEN_ELIGIBLE→SPIKE',
  'GREEN→SENSOR_RUN', 'GREEN→REFACTOR', 'GREEN→PENDING', 'GREEN→SPIKE',
  'SENSOR_RUN→SENSOR_FIX', 'SENSOR_RUN→SENSOR_CLEAN',
  'SENSOR_FIX→GREEN', 'SENSOR_FIX→RED',
  'SENSOR_CLEAN→REFACTOR', 'SENSOR_CLEAN→PENDING', 'SENSOR_CLEAN→SPIKE',
  'REFACTOR→GREEN', 'REFACTOR→PENDING', 'REFACTOR→SPIKE',
  'SPIKE→PENDING',
  // delegated-path compound edges (agent compresses micro-states)
  'PENDING→RED_VERIFIED',
  'RED_VERIFIED→GREEN',
  'GREEN→SENSOR_CLEAN',
]);
const TERMINAL_STATES = new Set(['SENSOR_CLEAN', 'REFACTOR', 'PENDING', 'SPIKE']);

const TRIVIAL_OUTPUT = /^\s*(ok|pass(ed)?)\s*$/i;
const VALID_SENSOR_STATUSES = new Set(['pass', 'fail', 'timeout', 'not_applicable', 'skipped']);
const SENSOR_METADATA_KEYS = new Set(['ecosystem', 'detected_at', 'summary']);

function normalizeDiff(s) {
  if (!s) return '';
  return s
    .split('\n')
    .filter((line) => !/^index\s+[0-9a-f]+\.\.[0-9a-f]+/.test(line))
    .join('\n')
    .replace(/\s+$/g, '')
    .replace(/\n+$/g, '');
}

function runGit(args, cwd) {
  try {
    return execFileSync('git', args, {
      cwd,
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'pipe'],
    });
  } catch (e) {
    return '';
  }
}

function filesChanged(repo_root, before, after) {
  if (!before || !after) return [];
  const out = runGit(['diff', '--name-only', `${before}..${after}`], repo_root);
  return out.split('\n').filter(Boolean);
}

function getSensorStatus(value) {
  if (typeof value === 'string') return value;
  if (value && typeof value === 'object' && typeof value.status === 'string') return value.status;
  return null;
}

function hasNotApplicableReason(value) {
  if (!value || typeof value !== 'object') return false;
  const reason = value.reason || value.evidence || value.message;
  if (typeof reason !== 'string' || reason.trim() === '') return false;
  return /not installed|not_installed|unavailable|missing|no .*tool|tool .*not/i.test(reason);
}

function validateSensorResults(sensorResults, sliceId) {
  const errors = [];
  if (!sensorResults || typeof sensorResults !== 'object' || Array.isArray(sensorResults)) {
    errors.push(`[item 4] ${sliceId}: sensor_results missing`);
    return errors;
  }

  const entries = Object.entries(sensorResults);
  if (entries.length === 0) {
    errors.push(`[item 4] ${sliceId}: sensor_results empty`);
    return errors;
  }

  let sensorCount = 0;
  for (const [name, value] of entries) {
    if (SENSOR_METADATA_KEYS.has(name)) continue;
    sensorCount++;
    const status = getSensorStatus(value);
    if (!VALID_SENSOR_STATUSES.has(status)) {
      errors.push(`[item 4] ${sliceId}: sensor_results.${name} has invalid status "${status ?? String(value)}"`);
      continue;
    }
    if (status === 'fail' || status === 'timeout') {
      errors.push(`[item 4] ${sliceId}: required sensor ${name} reported ${status}`);
    }
    if (status === 'not_applicable' && !hasNotApplicableReason(value)) {
      errors.push(`[item 4] ${sliceId}: sensor_results.${name} not_applicable requires tool-unavailable reason`);
    }
  }
  if (sensorCount === 0) {
    errors.push(`[item 4] ${sliceId}: sensor_results contains no sensor status entries`);
  }

  return errors;
}

function verifyReceipts({
  receipts,
  plan,
  tdd_mode = 'strict',
  repo_root = process.env.REPO_ROOT || process.cwd(),   // W13 — env-var override
  skip_items = [],                                       // C7 — inline path partial verify
  skip_git_checks = false,
  skip_diff_match = false,
} = {}) {
  const skip = new Set(skip_items);
  const errors = [];
  const slices = plan && Array.isArray(plan.slices) ? plan.slices : [];
  const bySliceId = new Map(slices.map((s) => [s.id, s]));

  // Item 1: file existence / count
  if (!skip.has(1) && receipts.length !== slices.length) {
    errors.push(`[item 1] slice count mismatch: ${receipts.length} receipts vs ${slices.length} slices`);
  }

  for (const r of receipts) {
    const slice = bySliceId.get(r.slice_id);
    if (!slice) {
      errors.push(`[item 1] receipt ${r.slice_id} has no matching slice in plan`);
      continue;
    }

    // Item 2: status (F10 — no blocked pass)
    if (!skip.has(2) && r.status !== 'complete') {
      errors.push(`[item 2] ${r.slice_id}: status="${r.status}" not allowed (F10 — only "complete")`);
    }

    // Item 3: tdd_state transitions (strict)
    if (!skip.has(3) && tdd_mode === 'strict') {
      const t = (r.tdd && r.tdd.state_transitions) || [];
      for (let i = 0; i < t.length - 1; i++) {
        const edge = `${t[i]}→${t[i + 1]}`;
        if (!STRICT_TRANSITIONS.has(edge)) {
          errors.push(`[item 3] ${r.slice_id}: invalid transition ${edge}`);
        }
      }
      const last = t[t.length - 1];
      if (last && !TERMINAL_STATES.has(last)) {
        errors.push(`[item 3] ${r.slice_id}: non-terminal final state "${last}"`);
      }
    }

    // Item 4: sensor_results present and semantically valid
    if (!skip.has(4)) {
      errors.push(...validateSensorResults(r.sensor_results, r.slice_id));
    }

    // Item 7: TDD hard-fail
    if (!skip.has(7)) {
      const rvo = r.tdd && r.tdd.red_verification_output;
      if (!rvo || typeof rvo !== 'string' || rvo.trim() === '') {
        errors.push(`[item 7] ${r.slice_id}: red_verification_output missing or empty`);
      } else if (TRIVIAL_OUTPUT.test(rvo)) {
        errors.push(`[item 7] ${r.slice_id}: red_verification_output trivial ("${rvo.trim()}") — must contain real FAIL evidence`);
      }
    }

    // Item 5: out-of-scope (unfiltered)
    if (!skip.has(5) && !skip_git_checks) {
      const touched = filesChanged(repo_root, r.git_before_slice, r.git_after_slice);
      const declared = new Set(slice.files || []);
      const outOfScope = touched.filter((f) => !declared.has(f));
      if (outOfScope.length > 0) {
        errors.push(`[item 5] ${r.slice_id}: out-of-scope edits: ${outOfScope.join(', ')}`);
      }

      if (!skip_diff_match && r.changes && typeof r.changes.git_diff === 'string' && r.changes.git_diff) {
        const actual = runGit(
          ['diff', '--no-color', '--patch', `${r.git_before_slice}..${r.git_after_slice}`],
          repo_root
        );
        if (normalizeDiff(actual) !== normalizeDiff(r.changes.git_diff)) {
          errors.push(`[item 5] ${r.slice_id}: recorded changes.git_diff does not match actual git diff`);
        }
      }
    }
  }

  // Item 6: baseline chain continuity — per-cluster (CA4 fix).
  // Team parallel mode: each cluster's receipts form an independent chain
  // starting from the shared delegation_snapshot. Verifying globally across
  // all receipts would false-fail legitimate parallel runs. Group by
  // receipt.cluster_id and check continuity within each group only.
  // Solo mode: all receipts share the same cluster_id (or undefined → treated
  // as one group) so behavior matches previous global chain check.
  if (!skip.has(6)) {
    const byCluster = new Map();
    for (const r of receipts) {
      const cid = r.cluster_id || '_default';
      if (!byCluster.has(cid)) byCluster.set(cid, []);
      byCluster.get(cid).push(r);
    }
    for (const [cid, group] of byCluster) {
      const sorted = [...group].sort((a, b) =>
        (a.slice_id || '').localeCompare(b.slice_id || '')
      );
      for (let i = 0; i < sorted.length - 1; i++) {
        const cur = sorted[i];
        const nxt = sorted[i + 1];
        if (cur.git_after_slice && nxt.git_before_slice && cur.git_after_slice !== nxt.git_before_slice) {
          errors.push(
            `[item 6] baseline chain break in cluster "${cid}": ${cur.slice_id}.git_after_slice="${cur.git_after_slice}" ≠ ${nxt.slice_id}.git_before_slice="${nxt.git_before_slice}"`
          );
        }
      }
    }
  }

  // Item 8: recorded verification_output vs expected_output.
  //   - structural errors (missing fields) → real fail
  //   - value mismatch → ADVISORY warning (N-R5 trust boundary)
  // Note (W-2.1): `checkItem8` is defined later in this file but is a
  // function declaration, so it IS hoisted to module scope and accessible
  // here at call time. The `typeof` guard exists for defensive early-load
  // scenarios; if someone ever converts `function checkItem8` to
  // `const checkItem8 = ...`, hoisting breaks and item 8 would silently
  // skip — unit test `checkItem8 invoked` asserts it runs.
  const warnings = [];
  if (!skip.has(8) && typeof checkItem8 === 'function') {
    const r = checkItem8(receipts);
    errors.push(...r.errors);
    warnings.push(...r.warnings);
  }

  return { pass: errors.length === 0, errors, warnings };
}

module.exports = {
  verifyReceipts,
  normalizeDiff,
  VERIFICATION_ITEMS,
  validateSensorResults,
};

